import sys, pykwavers as kw, numpy as np; grid=kw.Grid(16,16,16,1,1,1); med=kw.Medium.homogeneous(1500,1000); p0=np.zeros((16,16,16)); p0[8,8,8]=1; src=kw.Source.from_initial_pressure(p0); sm=np.zeros((16,16,16), dtype=bool); sm[8,8,8]=True; sen=kw.Sensor.from_mask(sm); sim=kw.Simulation(grid,med,src,sen,solver=kw.SolverType.PSTD); r=sim.run(time_steps=100); print('\n\nSHAPE:', r.sensor_data.shape); sys.stdout.flush()
